import { Link, useLocation } from 'react-router-dom';
import '../styles/navbar.css';
import { useState, useEffect } from 'react';

function Navbar() {
  const [menuOpen, setMenuOpen] = useState(false);
  const [scrolled, setScrolled] = useState(false);
  const location = useLocation();

  // Add shadow when scrolling
  useEffect(() => {
    const handleScroll = () => {
      setScrolled(window.scrollY > 50);
    };
    window.addEventListener("scroll", handleScroll);
  }, []);

  return (
    <nav className={scrolled ? "navbar scrolled" : "navbar"}>

      {/* LOGO */}
      <div className="logo">
        <img 
          src="https://cdn-icons-png.flaticon.com/512/2967/2967350.png" 
          alt="logo"
        />
        <div>
          <h2>JOY PURVEYORS</h2>
          <span>Medical Centre</span>
        </div>
      </div>

      {/* MENU TOGGLE */}
      <div className="menu-toggle" onClick={() => setMenuOpen(!menuOpen)}>
        ☰
      </div>

      {/* NAV LINKS */}
      <ul className={menuOpen ? "nav-links active" : "nav-links"}>

        <li>
          <Link className={location.pathname === "/" ? "active" : ""} to="/">Home</Link>
        </li>

        <li>
          <Link className={location.pathname === "/about" ? "active" : ""} to="/about">About</Link>
        </li>

        {/* DROPDOWN */}
        <li className="dropdown">
          <span>Services ▾</span>
          <ul className="dropdown-menu">
            <li><Link to="/services">All Services</Link></li>
            <li><Link to="/services">Maternity</Link></li>
            <li><Link to="/services">Dental</Link></li>
            <li><Link to="/services">Pharmacy</Link></li>
          </ul>
        </li>

        <li>
          <Link className={location.pathname === "/contact" ? "active" : ""} to="/contact">Contact</Link>
        </li>

        <li>
          <Link to="/appointment" className="btn-book">Book Appointment</Link>
        </li>

      </ul>

      {/* RIGHT SIDE ACTIONS */}
      <div className="nav-actions">
        <a href="tel:0733519526" className="call-btn">📞 +254 733 519 526</a>
        <a href="https://wa.me/254733519526" className="whatsapp-btn">💬</a>
      </div>

    </nav>
  );
}

export default Navbar;
